def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 1:
            penalty = 0
            for k in range(1, 5):
                pow_val = ratio ** (2 * k + 1)
                if k % 2 == 0:
                    penalty += pow_val / (k * 3)
                else:
                    penalty -= pow_val / (k * 2)
            base_score = ratio ** 4 + penalty
            adjustment = 1
            for n in range(1, 4):
                adjustment *= (1 + (ratio / (n + 1)))
            priorities[i] = base_score * adjustment
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = -1 if j % 3 == 0 else 1
                term = sign * (ratio ** j) / (j * 1.5)
                score += term
                if term < 0.01:
                    break
            multiplier = 20 if ratio < 0.2 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 4
            priorities[i] = abs(score) * multiplier
            if ratio > 0.85:
                extra = 0
                for m in range(1, 6):
                    if m % 2 == 0:
                        extra += (ratio ** m) / (m * 2)
                    else:
                        extra -= (ratio ** m) / (m + 1)
                priorities[i] += abs(extra)
            if priorities[i] > 15:
                priorities[i] = np.sqrt(priorities[i]) * 3
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    for idx in range(len(priorities)):
        if priorities[idx] != np.inf and priorities[idx] < 0.1:
            adjustments = [priorities[j] for j in range(len(priorities)) if priorities[j] > priorities[idx]]
            if adjustments:
                factor = sum(adjustments) / len(adjustments)
                priorities[idx] += factor * 0.05
    return priorities
